import Foundation
import SwiftUI
import ActivityKit
import AppIntents

extension Notification.Name {
    static let turnOffSignalization = Notification.Name(rawValue: "TurnOffSignalization")
}

struct RadiacodeWidgetExtensionAttributes: ActivityAttributes {

    public struct ContentState: Codable, Hashable {
        struct RadiationLevelModel: Codable, Hashable {

            struct ChartData: Codable, Hashable {
                let count: Float
                let time: Double

                static func == (lhs: ChartData, rhs: ChartData) -> Bool {
                    lhs.time == rhs.time
                }
            }
            var value: Float?
            var chartData: [ChartData]
        }

        var countRateModel: RadiationLevelModel
        var doseRateModel: RadiationLevelModel
        var signalizationTime: Date?
        var countRateLevel: SignalizationAlarmLevel
        var doseRateLevel: SignalizationAlarmLevel
        var activeRadiationType: RadiationType.Level
        var isReconnecting: Bool
    }
}

struct TurnOffIntent: LiveActivityIntent {
    static let title: LocalizedStringResource = "Turn Off Signalization"

    func perform() async throws -> some IntentResult {
        NotificationCenter.default.post(name: .turnOffSignalization, object: nil)
        return .result()
    }
}

